int  active()
{
    int ret = next active();

    if(ETGACFParameters::find().EnableProvisionalCharges == NoYes::Yes)
    {
        FormDataSource markUpTransDS = this;
        MarkupTrans    markupTrans   = this.cursor();
        if(markupTrans.ETGProvisionalCharges == NoYes::Yes)
        {
            markUpTransDS.allowCreate(false);
            markUpTransDS.allowEdit(false);
            markUpTransDS.allowDelete(false);
        }
    }

    return ret;
}
